import{_ as e}from"./plugin-vue_export-helper.21dcd24c.js";import{d as r}from"./app.b5fbf071.js";const s={},a=r('<h1 id="serverless" tabindex="-1"><a class="header-anchor" href="#serverless" aria-hidden="true">#</a> Serverless</h1><h2 id="\u4EC0\u4E48\u662Fserverless" tabindex="-1"><a class="header-anchor" href="#\u4EC0\u4E48\u662Fserverless" aria-hidden="true">#</a> \u4EC0\u4E48\u662FServerless</h2><p>Serverless \u80FD\u89E3\u51B3\u4EC0\u4E48\u95EE\u9898\uFF1F</p><p><u>\u7406\u6E05 Serverless \u8981\u89E3\u51B3\u7684\u95EE\u9898\u5176\u5B9E\u5F88\u7B80\u5355\uFF0C\u6211\u4EEC\u53EF\u4EE5\u4ECE\u5B57\u9762\u4E0A\u628A\u5B83\u62C6\u5F00\u6765\u770B\u3002Server \u8FD9\u91CC\u6307\u670D\u52A1\u7AEF\uFF0C\u5B83\u662F Serverless \u89E3\u51B3\u95EE\u9898\u7684\u8FB9\u754C\uFF1B\u800C less \u6211\u4EEC\u53EF\u4EE5\u7406\u89E3\u4E3A\u8F83\u5C11\u5173\u5FC3\uFF0C\u5B83\u662F Serverless \u89E3\u51B3\u95EE\u9898\u7684\u76EE\u7684\u3002\u7EC4\u5408\u5728\u4E00\u8D77\u5C31\u662F\u201C\u8F83\u5C11\u5173\u5FC3\u670D\u52A1\u7AEF\u201D\u3002\u600E\u4E48\u7406\u89E3\u8FD9\u53E5\u8BDD\u5462\uFF1F\u6211\u4EEC\u4F9D\u7136\u662F\u62C6\u5F00\u6765\u5206\u6790\u3002</u></p><p>\u6211\u4EEC\u53EF\u4EE5\u5148\u770B Serverfull \u7684\u6982\u5FF5\uFF0C\u5BF9\u6BD4 Serverfull \u548C Serverless \u4E4B\u95F4\u7684\u5DEE\u522B\uFF0C\u76F8\u4FE1\u8FD9\u6837\u53EF\u4EE5\u52A0\u6DF1\u4F60\u7684\u7406\u89E3\u3002Serverfull \u5C31\u662F\u670D\u52A1\u7AEF\u8FD0\u7EF4\u5168\u7531\u6211\u4EEC\u81EA\u5DF1\u8D1F\u8D23\uFF0CServerless \u5219\u662F\u670D\u52A1\u7AEF\u8FD0\u7EF4\u8F83\u5C11\u7531\u6211\u4EEC\u81EA\u5DF1\u8D1F\u8D23\uFF0C\u5927\u591A\u6570\u7684\u8FD0\u7EF4\u5DE5\u4F5C\u4EA4\u7ED9\u81EA\u52A8\u5316\u5DE5\u5177\u8D1F\u8D23\u3002</p><p>\u65F6\u4EE3\u5212\u5206\uFF1A</p><ol><li><p>\u53F2\u524D\u65F6\u4EE3\uFF0CServerfull\uFF1A</p><p>\u8FD9\u4E2A\u65F6\u4EE3\u7814\u53D1\u548C\u8FD0\u7EF4\u9694\u79BB\uFF0C\u670D\u52A1\u7AEF\u8FD0\u7EF4\u90FD\u4EA4\u7ED9\u5C0F\u670D\u4E00\u4E2A\u4EBA\uFF0C\u7EAF\u4EBA\u529B\u5904\u7406\uFF0C\u4E5F\u5C31\u662F Serverfull\u3002</p></li><li><p>\u519C\u8015\u65F6\u4EE3\uFF0CDevOps:</p><p>\u8FD9\u4E2A\u65F6\u4EE3\u5C31\u662F\u7814\u53D1\u517C\u8FD0\u7EF4 DevOps\uFF0C\u5C0F\u7A0B\u517C\u4EFB\u4E86\u5C0F\u670D\u7684\u90E8\u5206\u5DE5\u4F5C\uFF0C\u5C0F\u670D\u5C06\u90E8\u5206\u670D\u52A1\u7AEF\u8FD0\u7EF4\u7684\u5DE5\u4F5C\u5DE5\u5177\u5316\u4E86\uFF0C\u81EA\u5DF1\u53EF\u4EE5\u53BB\u505A\u66F4\u52A0\u4E13\u4E1A\u7684\u4E8B\u60C5\u3002</p></li><li><p>\u5DE5\u4E1A\u65F6\u4EE3</p><p>\u8FD9\u65F6\uFF0C\u5C0F\u670D\u53D1\u73B0\u8D44\u6E90\u4F18\u5316\u548C\u6269\u7F29\u5BB9\u65B9\u6848\u4E5F\u53EF\u4EE5\u5229\u7528\u6027\u80FD\u76D1\u63A7 + \u6D41\u91CF\u4F30\u7B97\u89E3\u51B3\u3002\u5C0F\u670D\u53C8\u57FA\u4E8E\u5C0F\u7A0B\u7684\u5F00\u53D1\u6D41\u7A0B\uFF0COpsConsole \u7CFB\u7EDF\u518D\u8FDB\u4E00\u6B65\uFF0C\u5E2E\u5C0F\u7A0B\u505A\u4E86\u4E00\u5957\u4EE3\u7801\u81EA\u52A8\u5316\u53D1\u5E03\u7684\u6D41\u6C34\u7EBF\uFF1A\u4EE3\u7801\u626B\u63CF - \u6D4B\u8BD5 - \u7070\u5EA6\u9A8C\u8BC1 - \u4E0A\u7EBF\u3002\u73B0\u5728\u7684\u5C0F\u7A0B\u8FDE OpsConsole \u90FD\u4E0D\u7528\u767B\u9646\u64CD\u4F5C\uFF0C\u53EA\u8981\u5C06\u6700\u65B0\u7684\u4EE3\u7801\u5408\u5E76\u5230 Git \u4ED3\u5E93\u6307\u5B9A\u7684 develop \u5206\u652F\uFF0C\u5269\u4E0B\u7684\u5C31\u90FD\u7531\u6D41\u6C34\u7EBF\u81EA\u52A8\u5316\u5904\u7406\u53D1\u5E03\u4E0A\u7EBF\u4E86\u3002\u8FD9\u4E2A\u65F6\u4EE3\u7814\u53D1\u4E0D\u9700\u8981\u8FD0\u7EF4\u4E86\uFF0C\u514D\u8FD0\u7EF4 NoOps\u3002</p></li><li><p>\u672A\u6765\uFF1A</p><p>\u5B9E\u73B0\u4E86\u514D\u8FD0\u7EF4 NoOps\uFF0C\u514D\u8FD0\u7EF4 NoOps \u5E76\u4E0D\u662F\u8BF4\u670D\u52A1\u7AEF\u8FD0\u7EF4\u5C31\u4E0D\u5B58\u5728\u4E86\uFF0C\u800C\u662F\u901A\u8FC7\u5168\u77E5\u5168\u80FD\u7684\u670D\u52A1\uFF0C\u8986\u76D6\u7814\u53D1\u90E8\u7F72\u9700\u8981\u7684\u6240\u6709\u9700\u6C42\uFF0C\u8BA9\u7814\u53D1\u540C\u5B66\u5C0F\u7A0B\u5BF9\u5B83\u7684\u611F\u77E5\u8D8A\u6765\u8D8A\u5C11\u3002\u53E6\u5916\uFF0CNoOps \u662F\u7406\u60F3\u72B6\u6001\uFF0C\u56E0\u4E3A\u6211\u4EEC\u53EA\u80FD\u65E0\u9650\u903C\u8FD1 NoOps\uFF0C\u6240\u4EE5\u8FD9\u4E2A\u5355\u8BCD\u662F less\uFF0C\u4E0D\u53EF\u80FD\u662F ServerLeast \u6216\u8005 ServerZero\u3002</p></li></ol><p>Server \u9650\u5B9A\u4E86 Serverless \u89E3\u51B3\u95EE\u9898\u7684\u8FB9\u754C\uFF0C\u5373\u670D\u52A1\u7AEF\u8FD0\u7EF4\uFF1Bless \u8BF4\u660E\u4E86 Serverless \u89E3\u51B3\u95EE\u9898\u7684\u76EE\u7684\uFF0C\u5373\u514D\u8FD0\u7EF4 NoOps\u3002\u6240\u4EE5\u6211\u4EEC\u91CD\u65B0\u7EC4\u5408\u4E00\u4E0B\u8FD9\u4E2A\u8BCD\u7684\u8BDD\uFF0CServerless \u5C31\u5E94\u8BE5\u53EB\u505A\u670D\u52A1\u7AEF\u514D\u8FD0\u7EF4\u3002\u8FD9\u4E5F\u5C31\u662F Serverless \u8981\u89E3\u51B3\u7684\u95EE\u9898\u3002</p><h3 id="\u5230\u5E95\u4EC0\u4E48\u662F-serverless" tabindex="-1"><a class="header-anchor" href="#\u5230\u5E95\u4EC0\u4E48\u662F-serverless" aria-hidden="true">#</a> \u5230\u5E95\u4EC0\u4E48\u662F Serverless?</h3><p><strong>\u7B2C\u4E00\u79CD\uFF1A\u72ED\u4E49 Serverless\uFF08\u6700\u5E38\u89C1\uFF09= Serverless computing \u67B6\u6784 = FaaS \u67B6\u6784 = Trigger\uFF08\u4E8B\u4EF6\u9A71\u52A8\uFF09+ FaaS\uFF08\u51FD\u6570\u5373\u670D\u52A1\uFF09+ BaaS\uFF08\u540E\u7AEF\u5373\u670D\u52A1\uFF0C\u6301\u4E45\u5316\u6216\u7B2C\u4E09\u65B9\u670D\u52A1\uFF09= FaaS + BaaS</strong></p><p><strong>\u7B2C\u4E8C\u79CD\uFF1A\u5E7F\u4E49 Serverless = \u670D\u52A1\u7AEF\u514D\u8FD0\u7EF4 = \u5177\u5907 Serverless \u7279\u6027\u7684\u4E91\u670D\u52A1</strong></p><p><img src="https://my-doc-1259409954.file.myqcloud.com/MyImages/ff0f26ec67f6455dfc142c2943da0028.png" alt="img"></p><h4 id="faas" tabindex="-1"><a class="header-anchor" href="#faas" aria-hidden="true">#</a> FaaS</h4><p>\u5148\u8BF4 FaaS\uFF0C\u51FD\u6570\u5373\u670D\u52A1\uFF0C\u5B83\u8FD8\u6709\u4E2A\u540D\u5B57\u53EB\u4F5C Serverless Computing\uFF0C\u5B83\u53EF\u4EE5\u8BA9\u6211\u4EEC\u968F\u65F6\u968F\u5730\u521B\u5EFA\u3001\u4F7F\u7528\u3001\u9500\u6BC1\u4E00\u4E2A\u51FD\u6570\u3002</p><p>FaaS \u7684 Runtime \u662F\u9884\u5148\u8BBE\u7F6E\u597D\u7684\uFF0CRuntime \u91CC\u9762\u52A0\u8F7D\u7684\u51FD\u6570\u548C\u8D44\u6E90\u90FD\u662F\u4E91\u670D\u52A1\u5546\u63D0\u4F9B\u7684\uFF0C\u6211\u4EEC\u53EF\u4EE5\u4F7F\u7528\u5374\u65E0\u6CD5\u63A7\u5236\u3002\u4F60\u53EF\u4EE5\u7406\u89E3\u4E3A FaaS \u7684 Runtime \u662F\u4E34\u65F6\u7684\uFF0C\u51FD\u6570\u8C03\u7528\u5B8C\u540E\uFF0C\u8FD9\u4E2A\u4E34\u65F6 Runtime \u548C\u51FD\u6570\u4E00\u8D77\u9500\u6BC1\u3002</p><p>FaaS \u7684\u51FD\u6570\u8C03\u7528\u5B8C\u540E\uFF0C\u4E91\u670D\u52A1\u5546\u4F1A\u9500\u6BC1\u5B9E\u4F8B\uFF0C\u56DE\u6536\u8D44\u6E90\uFF0C\u6240\u4EE5 FaaS \u63A8\u8350\u65E0\u72B6\u6001\u7684\u51FD\u6570\u3002\u5982\u679C\u4F60\u662F\u4E00\u4F4D\u524D\u7AEF\u5DE5\u7A0B\u5E08\u7684\u8BDD\uFF0C\u53EF\u80FD\u5F88\u597D\u7406\u89E3\uFF0C\u5C31\u662F\u51FD\u6570\u4E0D\u53EF\u6539\u53D8 Immutable\u3002\u7B80\u5355\u89E3\u91CA\u4E00\u4E0B\uFF0C\u5C31\u662F\u8BF4\u4E00\u4E2A\u51FD\u6570\u53EA\u8981\u53C2\u6570\u56FA\u5B9A\uFF0C\u8FD4\u56DE\u7684\u7ED3\u679C\u4E5F\u5FC5\u987B\u662F\u56FA\u5B9A\u7684\u3002</p><p>\u7528\u6211\u4EEC\u4E0A\u9762\u7684 MVC \u67B6\u6784\u7684 Web \u5E94\u7528\u4E3E\u4F8B\uFF0CView \u5C42\u662F\u5BA2\u6237\u7AEF\u5C55\u73B0\u7684\u5185\u5BB9\uFF0C\u901A\u5E38\u5E76\u4E0D\u9700\u8981\u51FD\u6570\u7B97\u529B\uFF1BControl \u5C42\uFF0C\u5C31\u662F\u51FD\u6570\u7684\u5178\u578B\u4F7F\u7528\u573A\u666F\u3002MVC \u67B6\u6784\u91CC\u9762\uFF0C\u4E00\u4E2A HTTP \u7684\u6570\u636E\u8BF7\u6C42\uFF0C\u5C31\u4F1A\u5BF9\u5E94\u4E00\u4E2A Control \u51FD\u6570\uFF0C\u6211\u4EEC\u5B8C\u5168\u53EF\u4EE5\u7528 FaaS \u51FD\u6570\u6765\u4EE3\u66FF Control \u51FD\u6570\u3002\u5728 HTTP \u7684\u6570\u636E\u8BF7\u6C42\u91CF\u5927\u7684\u65F6\u5019\uFF0CFaaS \u51FD\u6570\u4F1A\u81EA\u52A8\u6269\u5BB9\u591A\u5B9E\u4F8B\u540C\u65F6\u8FD0\u884C\uFF1B\u5728 HTTP \u7684\u6570\u636E\u8BF7\u6C42\u91CF\u5C0F\u65F6\uFF0C\u53C8\u4F1A\u81EA\u52A8\u7F29\u5BB9\uFF1B\u5F53\u6CA1\u6709 HTTP \u6570\u636E\u8BF7\u6C42\u65F6\uFF0C\u8FD8\u4F1A\u7F29\u5BB9\u5230 0 \u5B9E\u4F8B\uFF0C\u8282\u7701\u5F00\u652F\u3002</p><p><img src="https://my-doc-1259409954.file.myqcloud.com/MyImages/415a8dc0dc026fe2db71e2406e568ba6.png" alt="img"></p><p>\u6B64\u523B\u6216\u8BB8\u4F60\u4F1A\u6709\u70B9\u7591\u60D1\uFF0CRuntime \u4E0D\u53EF\u63A7\uFF0CFaaS \u51FD\u6570\u65E0\u72B6\u6001\uFF0C\u51FD\u6570\u7684\u5B9E\u4F8B\u53C8\u4E0D\u505C\u5730\u6269\u5BB9\u7F29\u5BB9\uFF0C\u90A3\u6211\u9700\u8981\u6301\u4E45\u5316\u5B58\u50A8\u4E00\u4E9B\u6570\u636E\u600E\u4E48\u529E\uFF0CMVC \u91CC\u9762\u7684 Model \u5C42\u600E\u4E48\u89E3\u51B3\uFF1F</p><h4 id="baas" tabindex="-1"><a class="header-anchor" href="#baas" aria-hidden="true">#</a> BaaS</h4><p>BaaS \u5176\u5B9E\u662F\u4E00\u4E2A\u96C6\u5408\uFF0C\u662F\u6307\u5177\u5907\u9AD8\u53EF\u7528\u6027\u548C\u5F39\u6027\uFF0C\u800C\u4E14\u514D\u8FD0\u7EF4\u7684\u540E\u7AEF\u670D\u52A1\u3002\u8BF4\u7B80\u5355\u70B9\uFF0C\u5C31\u662F\u4E13\u95E8\u652F\u6491 FaaS \u7684\u670D\u52A1\u3002FaaS \u5C31\u50CF\u9AD8\u94C1\u7684\u8F66\u5934\uFF0C\u5982\u679C\u6211\u4EEC\u7684\u540E\u7AEF\u670D\u52A1\u8FD8\u662F\u8001\u65E7\u7684\u7EFF\u76AE\u706B\u8F66\u8F66\u53A2\uFF0C\u90A3\u80AF\u5B9A\u662F\u8981\u6563\u67B6\u7684\uFF0C\u800C BaaS \u5C31\u662F\u4E13\u95E8\u4E3A FaaS \u51C6\u5907\u7684\u9AD8\u94C1\u8F66\u53A2\u3002</p><p>MVC \u67B6\u6784\u4E2D\u7684 Model \u5C42\uFF0C\u5C31\u9700\u8981\u6211\u4EEC\u7528 BaaS \u6765\u89E3\u51B3\u3002Model \u5C42\u6211\u4EEC\u4EE5 MySQL \u4E3A\u4F8B\uFF0C\u540E\u7AEF\u670D\u52A1\u6700\u597D\u662F\u5C06 FaaS \u64CD\u4F5C\u7684\u6570\u636E\u5E93\u7684\u547D\u4EE4\uFF0C\u5C01\u88C5\u6210 HTTP \u7684 OpenAPI\uFF0C\u63D0\u4F9B\u7ED9 FaaS \u8C03\u7528\uFF0C\u81EA\u5DF1\u63A7\u5236\u8FD9\u4E2A API \u7684\u8BF7\u6C42\u9891\u7387\u4EE5\u53CA\u9650\u6D41\u964D\u7EA7\u3002\u8FD9\u4E2A\u540E\u7AEF\u670D\u52A1\u672C\u8EAB\u5219\u53EF\u4EE5\u901A\u8FC7\u8FDE\u63A5\u6C60\u3001MySQL \u96C6\u7FA4\u7B49\u65B9\u5F0F\u53BB\u4F18\u5316\u3002\u5404\u5927\u4E91\u670D\u52A1\u5546\u81EA\u8EAB\u4E5F\u5728\u6539\u9020\u81EA\u5DF1\u7684\u540E\u7AEF\u670D\u52A1\uFF0CBaaS \u8FD9\u4E2A\u96C6\u5408\u4E5F\u5728\u65E5\u6E10\u58EE\u5927\u3002</p><p><img src="https://my-doc-1259409954.file.myqcloud.com/MyImages/f6fa8a879b34885d8037265bedbd2366.png" alt="img"></p><p>\u57FA\u4E8E Serverless \u67B6\u6784\uFF0C\u6211\u4EEC\u5B8C\u5168\u53EF\u4EE5\u628A\u4F20\u7EDF\u7684 MVC \u67B6\u6784\u8F6C\u6362\u4E3A BaaS+View+FaaS \u7684\u7EC4\u5408\uFF0C\u91CD\u6784\u6216\u5B9E\u73B0\u3002</p><blockquote><p>\u7B2C\u4E00\u79CD\uFF1A\u72ED\u4E49 Serverless\uFF08\u6700\u5E38\u89C1\uFF09= Serverless computing \u67B6\u6784 = FaaS \u67B6\u6784 = Trigger\uFF08\u4E8B\u4EF6\u9A71\u52A8\uFF09+ FaaS\uFF08\u51FD\u6570\u5373\u670D\u52A1\uFF09+ BaaS\uFF08\u540E\u7AEF\u5373\u670D\u52A1\uFF0C\u6301\u4E45\u5316\u6216\u7B2C\u4E09\u65B9\u670D\u52A1\uFF09= FaaS + BaaS</p></blockquote><p>\u800C\u5E7F\u4E49 Serverless\uFF0C\u5176\u5B9E\u5C31\u662F\u6307\u670D\u52A1\u7AEF\u514D\u8FD0\u7EF4\uFF0C\u4E5F\u662F\u672A\u6765\u7684\u4E3B\u8981\u8D8B\u52BF\u3002\u603B\u7ED3\u6765\u8BF4\u7684\u8BDD\u5C31\u662F\uFF0C\u6211\u4EEC\u65E5\u5E38\u8C08 Serverless \u7684\u65F6\u5019\uFF0C\u57FA\u672C\u90FD\u662F\u6307\u72ED\u4E49\u7684 Serverless\uFF0C\u4F46\u5F53\u6211\u4EEC\u63D0\u5230\u67D0\u4E2A\u670D\u52A1 Serverless \u5316\u7684\u65F6\u5019\uFF0C\u5F80\u5F80\u90FD\u662F\u6307\u5E7F\u4E49\u7684 Serverless\u3002\u6211\u4EEC\u540E\u9762\u7684\u8BFE\u7A0B\u4E2D\u4E5F\u662F\u5982\u6B64\u3002</p><h2 id="\u4E3A\u4EC0\u4E48\u963F\u91CC\u8981\u4E3E\u96C6\u56E2\u4E4B\u529B\u8D9F\u5751serverless" tabindex="-1"><a class="header-anchor" href="#\u4E3A\u4EC0\u4E48\u963F\u91CC\u8981\u4E3E\u96C6\u56E2\u4E4B\u529B\u8D9F\u5751serverless" aria-hidden="true">#</a> \u4E3A\u4EC0\u4E48\u963F\u91CC\u8981\u4E3E\u96C6\u56E2\u4E4B\u529B\u8D9F\u5751Serverless\uFF1F</h2><p>\u800C Serverless \u65E2\u53EF\u4EE5\u6EE1\u8DB3\u8D44\u6E90\u6700\u5927\u5316\u5229\u7528\u7684\u9700\u6C42\uFF0C\u4E5F\u80FD\u591F\u8C03\u4F18\u884C\u4E1A\u5185\u7684\u5F00\u53D1\u5C97\u4F4D\u5206\u5C42\u7ED3\u6784\uFF0C\u8BA9\u6BCF\u4E2A\u5F00\u53D1\u5C97\u4F4D\u90FD\u80FD\u591F\u5728\u6700\u9002\u5408\u81EA\u5DF1\u7684\u5730\u65B9\u53D1\u6325\u6700\u5927\u7684\u4EF7\u503C\u3002\u675C\u6B22\u8868\u793A\uFF0C\u963F\u91CC\u6B63\u662F\u56E0\u4E3A\u770B\u5230\u4E86\u7ECF\u6D4E\u4F53\u5185\u5B58\u5728\u7684\u4E0A\u8FF0\u95EE\u9898\uFF0C\u5728\u5C1D\u8BD5\u5BFB\u627E\u76F8\u5E94\u89E3\u51B3\u65B9\u6848\u7684\u8FC7\u7A0B\u4E2D\u53D1\u73B0 Serverless \u53EF\u80FD\u662F\u4E00\u4E2A\u597D\u7684\u89E3\u51B3\u65B9\u6848\uFF0C\u624D\u5F00\u59CB\u7814\u7A76 Serverless\uFF0C\u7814\u7A76\u540E\u8BA4\u4E3A\u786E\u5B9E\u53EF\u884C\uFF0C\u624D\u542F\u52A8\u4E86\u201C\u963F\u91CC\u5DF4\u5DF4\u7ECF\u6D4E\u4F53\u524D\u7AEF Serverless \u7814\u53D1\u5347\u7EA7\u9879\u76EE\u201D\u8FD9\u6837\u4E00\u4E2A\u9879\u76EE\uFF0C\u62C9\u4E0A\u5927\u5BB6\u4E00\u8D77\u6765\u5171\u5EFA\u3002</p><p>Serverless\uFF0CServerless \u5E94\u8BE5\u88AB\u5E7F\u6CDB\u5730\u8FD0\u7528\u5728\u4E0D\u540C\u7684\u573A\u666F\u548C\u5B9E\u9645\u5F00\u53D1\u9700\u6C42\u4E2D\u3002\u4ECE\u4E91\u5382\u5546\u7684\u89D2\u5EA6\u6765\u770B\uFF0C<strong>\u4E91\u8BA1\u7B97\u672A\u6765\u4E00\u5B9A\u4F1A\u6210\u4E3A\u6574\u4E2A\u793E\u4F1A\u548C\u5546\u4E1A\u7684\u57FA\u7840\u8BBE\u65BD\uFF0C\u5C4A\u65F6\u4F7F\u7528\u4E91\u8BA1\u7B97\u5C31\u5E94\u8BE5\u50CF\u73B0\u5728\u6211\u4EEC\u4F7F\u7528\u6C34\u7535\u7164\u4E00\u6837\u7B80\u5355\uFF0C\u4E0D\u9700\u8981\u4E86\u89E3\u6C34\u4ECE\u54EA\u91CC\u6765\u3001\u600E\u4E48\u8FC7\u6EE4\u3001\u600E\u4E48\u94FA\u8BBE\u7BA1\u9053\u7B49\u4E00\u7CFB\u5217\u95EE\u9898\uFF0C\u53EA\u9700\u8981\u6253\u5F00\u6C34\u9F99\u5934\u63A5\u4E00\u676F\u6C34\u800C\u5DF2\u3002</strong></p><p>\u800C Serverless \u7684\u6982\u5FF5\u6B63\u597D\u53EF\u4EE5\u5E2E\u52A9\u4E91\u8BA1\u7B97\u671D\u8FD9\u4E2A\u65B9\u5411\u5F80\u524D\u8D70\u4E00\u6B65\uFF0C**\u5B83\u63D0\u5021\u7684\u662F\u4EBA\u4EEC\u4E0D\u9700\u8981\u5173\u5FC3\u5E94\u7528\u903B\u8F91\u4EE5\u5916\u7684\u670D\u52A1\u76F8\u5173\u7684\u4E8B\u60C5\uFF0C\u5305\u62EC\u7BA1\u7406\u3001\u914D\u7F6E\u3001\u8FD0\u7EF4\u7B49\uFF0C\u7528\u591A\u5C11\u5C31\u4ED8\u591A\u5C11\u3002**\u4ECE\u8FD9\u4E2A\u89D2\u5EA6\u6765\u770B\uFF0CServerless \u662F\u771F\u6B63\u8BA9\u4E91\u8BA1\u7B97\u53D8\u6210\u793E\u4F1A\u5546\u4E1A\u57FA\u7840\u8BBE\u65BD\u7684\u4E00\u4E2A\u5B9E\u73B0\u8DEF\u5F84\uFF0C\u4E5F\u66F4\u63A5\u8FD1\u73B0\u5728\u4E1A\u5185\u63D0\u5021\u7684\u4E91\u539F\u751F\u7684\u65B9\u5F0F\uFF0C\u56E0\u6B64\u4EBA\u4EEC\u5728\u4F7F\u7528\u4E91\u8BA1\u7B97\u7684\u8FC7\u7A0B\u4E2D\u81EA\u7136\u5C31\u5E94\u8BE5\u6309\u7167 Serverless \u7684\u65B9\u5F0F\u6765\u4F7F\u7528\u3002</p><h3 id="\u524D\u7AEF\u5F00\u53D1\u8005\u770B\u597D\u3001\u540E\u7AEF\u5F00\u53D1\u8005\u89C2\u671B-serverless-\u4E3A\u4F55\u5982\u6B64" tabindex="-1"><a class="header-anchor" href="#\u524D\u7AEF\u5F00\u53D1\u8005\u770B\u597D\u3001\u540E\u7AEF\u5F00\u53D1\u8005\u89C2\u671B-serverless-\u4E3A\u4F55\u5982\u6B64" aria-hidden="true">#</a> \u524D\u7AEF\u5F00\u53D1\u8005\u770B\u597D\u3001\u540E\u7AEF\u5F00\u53D1\u8005\u89C2\u671B\uFF0CServerless \u4E3A\u4F55\u5982\u6B64\uFF1F</h3><p>\u524D\u7AEF\u5DE5\u7A0B\u5E08\u9664\u4E86\u8981\u4FDD\u6301\u5728 UI\u3001\u4EA4\u4E92\u903B\u8F91\u65B9\u9762\u7684\u4F18\u52BF\uFF0C\u8FD8\u8981\u7406\u89E3\u6574\u4E2A\u4E1A\u52A1\u548C\u4E1A\u52A1\u80CC\u540E\u7684\u610F\u56FE\uFF0C\u8FD9\u610F\u5473\u7740\u672A\u6765\u524D\u7AEF\u884C\u4E1A\u7684\u601D\u8003\u6A21\u5F0F\u4F1A\u53D8\u6210\u9762\u5411\u4E1A\u52A1\u7684\u601D\u8003\u6A21\u5F0F\u3002\u4E0E\u6B64\u540C\u65F6\uFF0C\u524D\u7AEF\u7684\u534F\u540C\u548C\u5F00\u53D1\u6A21\u5F0F\u3001\u4E0A\u4E0B\u6E38\u6D41\u7A0B\u4E5F\u4F1A\u53D1\u751F\u53D8\u5316\uFF0C\u539F\u6765\u524D\u7AEF\u53EF\u80FD\u5F88\u5C11\u8DDF\u4EA7\u54C1\u7ECF\u7406\u3001\u8BBE\u8BA1\u6253\u4EA4\u9053\uFF0C\u672A\u6765\u524D\u7AEF\u8981\u5BF9\u6574\u4E2A\u5E94\u7528\u8D1F\u8D23\uFF0C\u5C31\u9700\u8981\u5929\u5929\u8DDF\u4EA7\u54C1\u7ECF\u7406\u3001\u8BBE\u8BA1\u6253\u4EA4\u9053\u3002\u540E\u7AEF\u5219\u8981\u5728\u6700\u5E95\u5C42\u63D0\u4F9B\u66F4\u6DF1\u7684\u80FD\u529B\u4ED8\u51FA\uFF0C\u6BD4\u5982\u5982\u4F55\u6309\u7167\u4E00\u4EBF\u6D41\u91CF\u7684\u652F\u51FA\u652F\u6491\u5341\u4EBF\u6D41\u91CF\uFF0C\u8FD9\u662F\u66F4\u5927\u7684\u6311\u6218\u3002</p><blockquote><p>\u76EE\u524D Serverless \u6700\u4F73\u5B9E\u8DF5\u6A21\u5F0F\u5C1A\u672A\u51FA\u73B0</p><p>\u201C2020 \u5E74 Serverless \u4F1A\u8FDB\u5165\u521D\u6B65\u5B9E\u8DF5\u9636\u6BB5\uFF0C\u8FD8\u4E0D\u80FD\u79F0\u4E4B\u4E3A\u5927\u89C4\u6A21\u5B9E\u8DF5\uFF0C\u53EF\u80FD\u5230 2021 \u5E74\u624D\u4F1A\u8FDB\u5165\u5927\u89C4\u6A21\u5B9E\u8DF5\u9636\u6BB5\u3002\u5728\u8FD9\u4E2A\u8FC7\u7A0B\u5F53\u4E2D\uFF0C\u4E91\u5382\u5546\u4F1A\u8FDB\u4E00\u6B65\u8865\u5145\u66F4\u591A\u7684 Serverless \u670D\u52A1\uFF0C\u5305\u62EC\u4E00\u4E9B\u540E\u7AEF\u7684 BaaS \u670D\u52A1\uFF0C\u628A\u57FA\u7840\u6253\u5F97\u66F4\u7262\u4E00\u70B9\u3002\u201D</p></blockquote>',33);function l(p,S){return a}var i=e(s,[["render",l],["__file","serverless.html.vue"]]);export{i as default};
